// FIX #3: Redis Distributed Lock
// Предотвращает двойной запуск пайплайна

const LOCK_KEY = 'pipeline_lock:video-pipeline-nutra';
const LOCK_TTL = 600;
const LOCK_TOKEN = `nutra-${Date.now()}-${Math.random().toString(36).slice(2)}`;

const redis = $getWorkflowStaticData('global');

// Пытаемся захватить lock
const acquired = await $redis.set(LOCK_KEY, LOCK_TOKEN, 'EX', LOCK_TTL, 'NX');

if (!acquired) {
  const ttlLeft = await $redis.ttl(LOCK_KEY);
  console.log(`[Lock] Занят. Осталось ${ttlLeft}s. Пропускаем итерацию.`);
  return [{ json: { status: 'skipped', reason: 'lock_busy', ttl_left: ttlLeft } }];
}

// Сохраняем token для освобождения в конце
$execution.customData.set('lock_token', LOCK_TOKEN);
$execution.customData.set('lock_key', LOCK_KEY);
console.log('[Lock] Захвачен ✅');

return [{ json: { status: 'acquired', token: LOCK_TOKEN } }];

const lockKey   = $execution.customData.get('lock_key');
const lockToken = $execution.customData.get('lock_token');

if (lockKey && lockToken) {
  const lua = `if redis.call('get', KEYS[1]) == ARGV[1] then return redis.call('del', KEYS[1]) else return 0 end`;
  const result = await $redis.eval(lua, 1, lockKey, lockToken);
  console.log(result === 1 ? '[Lock] Освобождён ✅' : '[Lock] Уже истёк');
}
return [{ json: { status: 'done' } }];
